def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score += 2000 + 50 * (ratio - 2)**3
        elif 1 < ratio <= 2:
            score += 500 + 20 * (ratio - 1)**2
        else:
            if ratio > 0.9:
                score += 80 * ratio
            elif ratio > 0.7:
                score += 60 * ratio
            elif ratio > 0.4:
                score += 30 * ratio
            else:
                score += 5 * ratio
            if capacity < 5:
                score += 20
            elif capacity < 20:
                score += 10
            elif capacity > 200:
                score -= 15
            else:
                score -= 5
        for j in range(1, i+1):
            if bins[j-1] > capacity:
                score += (bins[j-1] - capacity) * 0.1
            else:
                score -= (capacity - bins[j-1]) * 0.05
        if i % 3 == 0:
            priorities[i] = score * 1.15
        elif i % 3 == 1:
            priorities[i] = score * 0.85
        else:
            priorities[i] = score * 1.05
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        base = 100
    else:
        base = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = base + 200 + i * 10
    for _ in range(2):
        for i in range(1, len(priorities)):
            diff = priorities[i] - priorities[i-1]
            if diff > 50:
                priorities[i] -= 10
            elif diff < -50:
                priorities[i] += 10
    return priorities
